        {q:"Heating effect of current is used in:",opts:["Electric motor","Electric generator","Electric heater and iron","Voltmeter"],ans:2},
        {q:"Why are alloys used in heating elements instead of pure metals?",opts:["Alloys are cheaper","Alloys have higher resistivity and don't oxidise at high temperatures","Alloys conduct better","Alloys are lighter"],ans:1}
